import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import { poolPromise } from "../database/db.js";

export default function VentasPage() {
  const [productos, setProductos] = useState([]);
  const [clientes, setClientes] = useState([]);

  const [busquedaProducto, setBusquedaProducto] = useState("");
  const [productoSeleccionado, setProductoSeleccionado] = useState(null);

  const [clienteNombre, setClienteNombre] = useState("");
  const [cantidad, setCantidad] = useState(1);
  const [mensaje, setMensaje] = useState("");

  // 🆕 Estado del ticket generado
  const [ticket, setTicket] = useState(null);

  // 🆕 Control del modal
  const [mostrarTicket, setMostrarTicket] = useState(false);

  useEffect(() => {
    obtenerProductos();
    obtenerClientes();
  }, []);

  const obtenerProductos = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/productos");
      setProductos(res.data);
    } catch (err) {
      console.error("❌ Error al obtener productos:", err);
    }
  };

  const obtenerClientes = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/clientes");
      setClientes(res.data);
    } catch (err) {
      console.error("❌ Error al obtener clientes:", err);
    }
  };

  const buscarProducto = (nombre) => {
    setBusquedaProducto(nombre);
    const producto = productos.find(
      (p) =>
        (p.nombre || "").toLowerCase() === nombre.toLowerCase() ||
        (p.Nombre || "").toLowerCase() === nombre.toLowerCase()
    );
    setProductoSeleccionado(producto || null);
    setMensaje("");
  };

  const realizarVenta = async () => {
    if (!productoSeleccionado) {
      setMensaje("⚠️ Debes seleccionar un producto válido.");
      return;
    }

    if (productoSeleccionado.stock < cantidad) {
      setMensaje("❌ Stock insuficiente para realizar la venta.");
      return;
    }

    if (!clienteNombre.trim()) {
      setMensaje("⚠️ Ingresa el nombre del cliente.");
      return;
    }

    try {
      // Buscar cliente existente o crear nuevo
      let cliente = clientes.find(
        (c) =>
          (c.Nombre || c.nombre || "").toLowerCase() ===
          clienteNombre.toLowerCase()
      );

      if (!cliente) {
        const nuevoCliente = await axios.post(
          "http://localhost:5000/api/clientes",
          { Nombre: clienteNombre }
        );
        cliente = nuevoCliente.data;
      }

      // Registrar venta en backend
      const resVenta = await axios.post("http://localhost:5000/api/ventas", {
        ClienteID: cliente.ClienteID || cliente.id,
        ProductoID: productoSeleccionado.ProductoID || productoSeleccionado.id,
        Cantidad: cantidad,
      });

      // 🆕 Crear ticket en frontend con los datos requeridos
      const nuevoTicket = {
        numero: resVenta.data.numero || Date.now(), // correlativo si backend no envía
        fecha: new Date().toLocaleDateString(),
        hora: new Date().toLocaleTimeString(),
        emisor: {
          nombre: "Mi Empresa S.A.",
          nif: "NIT-123456789"
        },
        cliente: clienteNombre,
        producto: productoSeleccionado.Nombre || productoSeleccionado.nombre,
        cantidad,
        precioUnitario: productoSeleccionado.precio || productoSeleccionado.Precio,
        iva: 21, // % por defecto (puedes cambiar)
      };

      nuevoTicket.subtotal = nuevoTicket.precioUnitario * cantidad;
      nuevoTicket.ivaImporte = nuevoTicket.subtotal * (nuevoTicket.iva / 100);
      nuevoTicket.total = nuevoTicket.subtotal + nuevoTicket.ivaImporte;

      setTicket(nuevoTicket);
      setMostrarTicket(true);

      setMensaje("✅ Venta realizada correctamente.");
      setBusquedaProducto("");
      setProductoSeleccionado(null);
      setClienteNombre("");
      setCantidad(1);
      obtenerProductos(); // actualizar stock
    } catch (err) {
      console.error("❌ Error al realizar la venta:", err);
      setMensaje("❌ Error al procesar la venta.");
    }
  };

  const imprimirTicket = () => {
    const contenido = document.getElementById("ticketDiv").innerHTML;
    const ventana = window.open("", "PRINT", "height=600,width=400");
    ventana.document.write(contenido);
    ventana.document.close();
    ventana.focus();
    ventana.print();
  };

  return (
    <div className="container mt-5">

      <div className="card shadow p-4">
        <div className="row g-3">
          {/* Buscar producto */}
          <div className="col-md-6">
            <label className="form-label fw-semibold">Producto</label>
            <input
              type="text"
              className="form-control"
              placeholder="Buscar producto..."
              value={busquedaProducto}
              onChange={(e) => buscarProducto(e.target.value)}
              list="listaProductos"
            />
            <datalist id="listaProductos">
              {productos.map((p) => (
                <option key={p.ProductoID || p.id} value={p.Nombre || p.nombre} />
              ))}
            </datalist>
          </div>

          {/* Cliente */}
          <div className="col-md-6">
            <label className="form-label fw-semibold">Cliente</label>
            <input
              type="text"
              className="form-control"
              placeholder="Nombre del cliente..."
              value={clienteNombre}
              onChange={(e) => setClienteNombre(e.target.value)}
            />
          </div>

          {/* Cantidad */}
          <div className="col-md-4">
            <label className="form-label fw-semibold">Cantidad</label>
            <input
              type="number"
              min="1"
              className="form-control"
              value={cantidad}
              onChange={(e) => setCantidad(Number(e.target.value))}
            />
          </div>

          {/* Botón vender */}
          <div className="col-md-8 d-flex align-items-end">
            <button
              className="btn btn-success w-100"
              onClick={realizarVenta}
              disabled={!productoSeleccionado}
            >
              💰 Realizar Venta
            </button>
          </div>
        </div>

        {mensaje && (
          <div className="alert alert-info text-center mt-4">{mensaje}</div>
        )}
      </div>

      {/* 🆕 MODAL DEL TICKET */}
      {mostrarTicket && ticket && (
        <div className="modal fade show d-block" style={{ backgroundColor: "rgba(0,0,0,0.5)" }}>
          <div className="modal-dialog">
            <div className="modal-content">

              <div className="modal-header">
                <h5 className="modal-title">Ticket de Venta</h5>
                <button className="btn-close" onClick={() => setMostrarTicket(false)} />
              </div>

              <div className="modal-body" id="ticketDiv">
                <h5 className="text-center">🧾 Ticket de Venta</h5>
                <hr />

                <p><strong>Emisor:</strong> {ticket.emisor.nombre}</p>
                <p><strong>NIF/NIT:</strong> {ticket.emisor.nif}</p>
                <p><strong>Fecha:</strong> {ticket.fecha}</p>
                <p><strong>Hora:</strong> {ticket.hora}</p>

                <hr />
                <p><strong>Cliente:</strong> {ticket.cliente}</p>
                <p><strong>Producto:</strong> {ticket.producto}</p>
                <p><strong>Cantidad:</strong> {ticket.cantidad}</p>
                <p><strong>Precio unitario:</strong> {ticket.precioUnitario} €</p>
                <p><strong>Subtotal:</strong> {ticket.subtotal.toFixed(2)} €</p>
                <p><strong>IVA {ticket.iva}%:</strong> {ticket.ivaImporte.toFixed(2)} €</p>

                <hr />
                <h4>Total: {ticket.total.toFixed(2)} €</h4>

                <p className="text-muted mt-3">
                  Nº de secuencia: {ticket.numero}
                </p>
              </div>

              <div className="modal-footer">
                <button className="btn btn-primary" onClick={imprimirTicket}>
                  🖨️ Imprimir
                </button>
                <button className="btn btn-secondary" onClick={() => setMostrarTicket(false)}>
                  Cerrar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

    </div>
  );
}
